+/**
+ * Intent Router Plugin
+ *
+ * Smart query → agent/tool mapping using @ruvector/wasm semantic matching.
+ * Routes user intents to optimal handlers with confidence scoring.
+ *
+ * Features:
+ * - Semantic intent classification (<1ms)
+ * - Multi-label routing (can route to multiple handlers)
+ * - Confidence-based fallback
+ * - Intent history for optimization
+ * - Dynamic route learning
+ *
+ * @example
+ * ```typescript
+ * import { intentRouterPlugin } from '@claude-flow/plugins/examples/ruvector-plugins';
+ * await getDefaultRegistry().register(intentRouterPlugin);
+ * ```
+ */
+
+import {
+  PluginBuilder,
+  MCPToolBuilder,
+  HookBuilder,
+  HookEvent,
+  HookPriority,
+  Security,
+} from '../../src/index.js';
+
+// Import @ruvector/wasm for semantic matching
+// @ts-expect-error - @ruvector/wasm types may not be available
+import { VectorDB as RuVectorDB } from '@ruvector/wasm';
+
+// ============================================================================
+// Types
+// ============================================================================
+
+export interface Intent {
+  id: string;
+  pattern: string;
+  category: string;
+  handlers: IntentHandler[];
+  priority: number;
+  examples: string[];
+  embedding?: Float32Array;
+  metadata: {
+    createdAt: Date;
+    updatedAt: Date;
+    usageCount: number;
+    successRate: number;
+  };
+}
+
+export interface IntentHandler {
