+/**
+ * Semantic Code Search Plugin
+ *
+ * Index and search code semantically using @ruvector/wasm vector database.
+ * Enables natural language queries like "find functions that handle authentication".
+ *
+ * Features:
+ * - Index code chunks with embeddings
+ * - Natural language code search (<1ms with HNSW)
+ * - Symbol-aware chunking
+ * - Language-specific tokenization
+ * - Incremental indexing
+ *
+ * @example
+ * ```typescript
+ * import { semanticCodeSearchPlugin } from '@claude-flow/plugins/examples/ruvector-plugins';
+ * await getDefaultRegistry().register(semanticCodeSearchPlugin);
+ * ```
+ */
+
+import {
+  PluginBuilder,
+  MCPToolBuilder,
+  HookBuilder,
+  HookEvent,
+  HookPriority,
+  Security,
+} from '../../src/index.js';
+
+// Import @ruvector/wasm for production HNSW vector database
+// @ts-expect-error - @ruvector/wasm types may not be available
+import { VectorDB as RuVectorDB } from '@ruvector/wasm';
+
+// ============================================================================
+// Types
+// ============================================================================
+
+export interface CodeChunk {
+  id: string;
+  filePath: string;
+  content: string;
+  language: string;
+  startLine: number;
+  endLine: number;
+  symbolType?: 'function' | 'class' | 'method' | 'variable' | 'import' | 'type' | 'interface';
+  symbolName?: string;
+  embedding?: Float32Array;
+  metadata: {
+    size: number;
+    hash: string;
+    indexedAt: Date;
+    dependencies?: string[];
+  };
+}
+
+export interface CodeSearchResult {
+  chunk: CodeChunk;
+  similarity: number;
+  relevance: number;
+  highlights?: string[];
+}
+
+export interface CodeSearchOptions {
+  k?: number;
+  minSimilarity?: number;
+  languages?: string[];
+  symbolTypes?: CodeChunk['symbolType'][];
+  filePaths?: string[];
+  includeContent?: boolean;
+}
+
+// ============================================================================
+// RuVector WASM Interface
+// ============================================================================
+
+interface IVectorDB {
+  insert(vector: Float32Array, id: string, metadata?: Record<string, unknown>): string;
+  search(query: Float32Array, k: number): Array<{ id: string; score: number; metadata?: Record<string, unknown> }>;
+  get(id: string): { vector: Float32Array; metadata: Record<string, unknown> } | null;
+  delete(id: string): boolean;
+  size(): number;
+}
+
+async function createVectorDB(dimensions: number): Promise<IVectorDB> {
+  try {
+    const db = new RuVectorDB({
+      dimensions,
+      indexType: 'hnsw',
+      metric: 'cosine',
+      efConstruction: 200,
+      m: 16,
+    });
+    await db.initialize?.();
+    return db as IVectorDB;
+  } catch {
+    console.warn('[@claude-flow/plugins] @ruvector/wasm not available, using fallback');
+    return new FallbackVectorDB(dimensions);
+  }
+}
+
+class FallbackVectorDB implements IVectorDB {
+  private vectors = new Map<string, { vector: Float32Array; metadata: Record<string, unknown> }>();
+
+  constructor(private dimensions: number) {}
+
+  insert(vector: Float32Array, id: string, metadata: Record<string, unknown> = {}): string {
+    this.vectors.set(id, { vector, metadata });
+    return id;
+  }
+
+  search(query: Float32Array, k: number): Array<{ id: string; score: number; metadata?: Record<string, unknown> }> {
+    const results: Array<{ id: string; score: number; metadata?: Record<string, unknown> }> = [];
+    for (const [id, entry] of this.vectors) {
+      let dot = 0, normA = 0, normB = 0;
+      for (let i = 0; i < query.length; i++) {
+        dot += query[i] * entry.vector[i];
+        normA += query[i] * query[i];
+        normB += entry.vector[i] * entry.vector[i];
+      }
+      const score = dot / (Math.sqrt(normA) * Math.sqrt(normB) || 1);
+      results.push({ id, score, metadata: entry.metadata });
+    }
+    return results.sort((a, b) => b.score - a.score).slice(0, k);
+  }
+
+  get(id: string) { return this.vectors.get(id) ?? null; }
+  delete(id: string) { return this.vectors.delete(id); }
+  size() { return this.vectors.size; }
+}
+
+// ============================================================================
+// Semantic Code Search Core
+// ============================================================================
+
+export class SemanticCodeSearch {
+  private vectorDb: IVectorDB | null = null;
+  private chunks = new Map<string, CodeChunk>();
+  private fileIndex = new Map<string, Set<string>>();
+  private dimensions: number;
+  private nextId = 1;
+  private initPromise: Promise<void> | null = null;
+
+  constructor(dimensions: number = 768) {
+    this.dimensions = dimensions;
+  }
+
+  async initialize(): Promise<void> {
+    if (this.vectorDb) return;
