+      db.insert(embedding, id, {
+        filePath: chunk.filePath,
+        language: chunk.language,
+        symbolType: chunk.symbolType,
+        symbolName: chunk.symbolName,
+        startLine: chunk.startLine,
+        endLine: chunk.endLine,
