+    let currentChunk: string[] = [];
+    let chunkStartLine = 1;
+    let currentSymbol: { type: CodeChunk['symbolType']; name: string } | null = null;
+
+    for (let i = 0; i < lines.length; i++) {
+      const line = lines[i];
+      const lineNum = i + 1;
+      const symbol = this.detectSymbol(line, patterns);
