+      if (symbol && currentChunk.length > 0) {
+        chunks.push(this.createChunk(currentChunk.join('\n'), filePath, language, chunkStartLine, lineNum - 1, currentSymbol));
+        currentChunk = [];
+        chunkStartLine = lineNum;
+      }
